-- Patient level adherence 

CREATE VIEW vw_Patient_Adherence AS
SELECT
	patient_id,
	rx_id,
	MIN(refill_date) as therepy_start_date,
	MAX(refill_date) as therepy_end_date,
	SUM(quantity_days) as total_quantity_days,
	180 as window_days,
	CAST(SUM(quantity_days) AS FLOAT) /
    NULLIF(DATEDIFF(day,
                    MIN(refill_date),
                    MAX(refill_end_date)),0) AS MPR,
	CASE 
        WHEN CAST(SUM(quantity_days) AS FLOAT) /
             NULLIF(180,0) > 1
        THEN 1
        ELSE CAST(SUM(quantity_days) AS FLOAT) /
             NULLIF(180,0)
    END AS PDC,

    CASE 
        WHEN MAX(CASE WHEN gap_days > 30 THEN 1 ELSE 0 END) = 1
        THEN 1
        ELSE 0
    END AS ever_discontinued
FROM
	refill_cleaned
GROUP BY
	patient_id,
	rx_id;

SELECT * FROM vw_Patient_Adherence;
select * from prescriptions
select * from hcp
SELECT
	AVG(PDC) as avg_PDC
FROM
	vw_Patient_Adherence;

/*
avg_PDC
0.662761111111113
*/

SELECT COUNT(*) AS Patient
FROM vw_Patient_Adherence
WHERE PDC >= 0.8;

/*
Patient
259
*/

-- HCP adherence

SELECT 
    p.hcp_id,
    AVG(a.PDC) AS avg_pdc,
	COUNT(*) as Adherent
FROM vw_Patient_Adherence a
JOIN prescriptions p
ON a.rx_id = p.rx_id
GROUP BY p.hcp_id
HAVING AVG(a.PDC)>=0.8;

/*
