HCP150	0.844444444444445	6
HCP015	0.831111111111111	5
HCP008	0.822222222222222	6
*/

SELECT
    p.hcp_id,
    COUNT(*) AS total_patients,
    SUM(CASE WHEN a.PDC >= 0.8 THEN 1 ELSE 0 END) AS adherent_patients,
    AVG(a.PDC) AS avg_pdc,
    CAST(SUM(CASE WHEN a.PDC >= 0.8 THEN 1 ELSE 0 END) AS FLOAT) /
    COUNT(*) AS adherence_rate
FROM vw_Patient_Adherence a
JOIN prescriptions p
ON a.rx_id = p.rx_id
GROUP BY p.hcp_id;

