SELECT 
    p.hcp_id,
    COUNT(*) AS total_patients,
    SUM(CASE WHEN a.PDC >= 0.8 THEN 1 ELSE 0 END) AS adherent_patients,
    AVG(a.PDC) AS avg_pdc,
    CAST(SUM(CASE WHEN a.PDC >= 0.8 THEN 1 ELSE 0 END) AS FLOAT)/COUNT(*) AS adherence_rate
FROM vw_Patient_Adherence a
JOIN prescriptions p
ON a.rx_id = p.rx_id
GROUP BY p.hcp_id
HAVING COUNT(*) >= 5
ORDER BY adherence_rate DESC;

